INSERT INTO vendor_wiki_pages (app, screen, content, element_selectors)
VALUES
(
  'hubspot',
  'contact-detail',
  E'---\nlayer: vendor\napp: hubspot\nscreen: contact-detail\nversion: "2026"\nlast_updated: 2026-04-11\nsource: "manual-mapping-v1"\n---\n\n# HubSpot: Contact Detail Page\n\n## Navigation\nAccessed via: Contacts > Contacts > [Contact Name]\n\n## Overview\nThe contact detail page is the central hub for managing an individual contact in HubSpot CRM. It displays all known information about a person, including their communication history, associated companies, deals, and tickets. The left column shows the contact''s properties (name, email, phone, lifecycle stage, lead status), while the middle column displays the activity timeline, and the right column shows associations and attachments.\n\n## Key Fields\n- **Email**: Primary identifier. Displayed prominently at the top. Click to send an email directly.\n- **Phone Number**: Click-to-call enabled if calling is configured.\n- **Lifecycle Stage**: Dropdown. Values: Subscriber, Lead, MQL, SQL, Opportunity, Customer, Evangelist, Other.\n- **Lead Status**: Dropdown. Values: New, Open, In Progress, Open Deal, Unqualified, Attempted to Contact, Connected.\n- **Contact Owner**: Dropdown to assign the contact to a team member.\n- **Last Activity Date**: Auto-populated timestamp of the most recent interaction.\n\n## Common Actions\n- **Create Task**: Opens a task creation panel in the right sidebar. Assign due date, type, and priority.\n- **Create Note**: Adds a note to the contact''s activity timeline. Supports @mentions for team members.\n- **Log Activity**: Log a call, email, or meeting manually. Includes outcome and duration fields.\n- **Send Email**: Opens the email composer with the contact pre-populated as the recipient.\n- **Make a Call**: Initiates a call through HubSpot''s calling tool (requires calling integration).\n- **Schedule Meeting**: Opens the meeting scheduler with the contact pre-filled.\n\n## Related Panels\n- **Activity Timeline**: Chronological log of all emails, calls, meetings, tasks, notes, and form submissions.\n- **Deals**: Associated deals with stage, amount, and close date.\n- **Companies**: Linked company records.\n- **Tickets**: Support tickets associated with this contact.\n- **Conversations**: Live chat and chatbot interactions.\n\n## UI Element Selectors\n- Lifecycle Stage dropdown: `[data-selenium-test="property-input-lifecyclestage"]`\n- Lead Status dropdown: `[data-selenium-test="property-input-hs_lead_status"]`\n- Email property: `[data-selenium-test="property-input-email"]`\n- Create Task button: `[data-selenium-test="timeline-create-task"]`\n- Activity timeline: `[data-selenium-test="timeline"]`',
  '{"Lifecycle Stage": "[data-selenium-test=\"property-input-lifecyclestage\"]", "Lead Status": "[data-selenium-test=\"property-input-hs_lead_status\"]", "Email Property": "[data-selenium-test=\"property-input-email\"]", "Create Task": "[data-selenium-test=\"timeline-create-task\"]", "Activity Timeline": "[data-selenium-test=\"timeline\"]"}'::jsonb
),
(
  'hubspot',
  'contacts-list',
  E'---\nlayer: vendor\napp: hubspot\nscreen: contacts-list\nversion: "2026"\nlast_updated: 2026-04-11\nsource: "manual-mapping-v1"\n---\n\n# HubSpot: Contacts List View\n\n## Navigation\nAccessed via: Contacts > Contacts (main navigation)\n\n## Overview\nThe contacts list view displays all contacts in a filterable, sortable table. Users can search, apply saved filters, create custom views, and perform bulk actions. The default view shows contact name, email, phone, contact owner, and last activity date. Columns are customizable per user.\n\n## Key Features\n- **Search Bar**: Full-text search across all contact properties. Located at the top of the table.\n- **Filters**: Click "Advanced filters" to build complex filter criteria using any contact property. Supports AND/OR logic.\n- **Saved Views**: Create and switch between saved filter configurations. Shared views are visible to the entire team.\n- **Column Customization**: Click "Edit columns" to add, remove, or reorder table columns.\n- **Pagination**: Navigate through pages of results. Default page size is 25 records.\n\n## Common Actions\n- **Create Contact**: Button in the top-right corner. Opens a modal to enter contact details.\n- **Import**: Import contacts from CSV, spreadsheet, or sync from another app.\n- **Export**: Download the current filtered view as a CSV file.\n- **Bulk Edit**: Select multiple contacts with checkboxes, then use the toolbar for bulk property updates, list enrollment, or deletion.\n- **Bulk Delete**: Select contacts and click "Delete" in the bulk action toolbar. Requires confirmation.\n\n## Table Interactions\n- **Sort**: Click any column header to sort ascending/descending.\n- **Inline Edit**: Some properties can be edited directly in the table by clicking the cell.\n- **Quick Preview**: Hover over a contact name to see a preview card with key details.\n\n## UI Element Selectors\n- Search input: `[data-selenium-test="object-filter-search-input"]`\n- Create contact button: `[data-selenium-test="contacts-create-button"]`\n- Advanced filters: `[data-selenium-test="filter-button"]`\n- Table rows: `[data-selenium-test="table-row"]`\n- Bulk action toolbar: `[data-selenium-test="bulk-action-toolbar"]`',
  '{"Search Input": "[data-selenium-test=\"object-filter-search-input\"]", "Create Contact": "[data-selenium-test=\"contacts-create-button\"]", "Advanced Filters": "[data-selenium-test=\"filter-button\"]", "Table Row": "[data-selenium-test=\"table-row\"]", "Bulk Actions": "[data-selenium-test=\"bulk-action-toolbar\"]"}'::jsonb
),
(
  'hubspot',
  'company-detail',
  E'---\nlayer: vendor\napp: hubspot\nscreen: company-detail\nversion: "2026"\nlast_updated: 2026-04-11\nsource: "manual-mapping-v1"\n---\n\n# HubSpot: Company Detail Page\n\n## Navigation\nAccessed via: Contacts > Companies > [Company Name]\n\n## Overview\nThe company detail page provides a comprehensive view of an organization in HubSpot CRM. It aggregates data from associated contacts, deals, and tickets to give a complete picture of the business relationship. The layout mirrors the contact detail page: properties on the left, activity timeline in the center, and associations on the right.\n\n## Key Fields\n- **Company Name**: Primary identifier displayed at the top of the page.\n- **Company Domain Name**: The company''s website domain. Used for automatic contact-company association.\n- **Industry**: Dropdown with standard industry categories.\n- **Annual Revenue**: Currency field representing the company''s yearly revenue.\n- **Number of Employees**: Numeric field. Can be a range or exact number.\n- **Company Owner**: Dropdown to assign a team member as the owner.\n- **Lifecycle Stage**: Tracks the company''s position in the sales pipeline.\n- **City / State / Country**: Location fields for the company''s primary address.\n\n## Common Actions\n- **Add Contact**: Associate an existing contact or create a new one linked to this company.\n- **Create Deal**: Open a new deal pre-associated with this company.\n- **Create Note**: Add a note to the company''s activity timeline.\n- **Log Activity**: Log a call, email, or meeting. Activity is shared across associated contacts.\n- **Create Task**: Create a follow-up task linked to the company.\n\n## Related Panels\n- **Contacts**: All contacts associated with this company. Shows name, email, and job title.\n- **Deals**: Active and closed deals. Shows stage, amount, and close date.\n- **Tickets**: Support tickets from contacts at this company.\n- **Activity Timeline**: Aggregated activity from the company and all associated contacts.\n\n## UI Element Selectors\n- Company Name header: `[data-selenium-test="record-title"]`\n- Industry property: `[data-selenium-test="property-input-industry"]`\n- Add Contact button: `[data-selenium-test="associations-add-button-contacts"]`\n- Company Owner: `[data-selenium-test="property-input-hubspot_owner_id"]`\n- Create Deal: `[data-selenium-test="associations-add-button-deals"]`',
  '{"Company Name": "[data-selenium-test=\"record-title\"]", "Industry": "[data-selenium-test=\"property-input-industry\"]", "Add Contact": "[data-selenium-test=\"associations-add-button-contacts\"]", "Company Owner": "[data-selenium-test=\"property-input-hubspot_owner_id\"]", "Create Deal": "[data-selenium-test=\"associations-add-button-deals\"]"}'::jsonb
),
(
  'hubspot',
  'deal-detail',
  E'---\nlayer: vendor\napp: hubspot\nscreen: deal-detail\nversion: "2026"\nlast_updated: 2026-04-11\nsource: "manual-mapping-v1"\n---\n\n# HubSpot: Deal Detail Page\n\n## Navigation\nAccessed via: Sales > Deals > [Deal Name] (from board or list view)\n\n## Overview\nThe deal detail page tracks a single sales opportunity through your pipeline. The top of the page shows a visual pipeline stage indicator, allowing you to advance or regress the deal by clicking on stages. Below that, the familiar three-column layout presents deal properties, the activity timeline, and associations.\n\n## Key Fields\n- **Deal Name**: Primary identifier for the opportunity.\n- **Pipeline**: Dropdown to select which sales pipeline this deal belongs to.\n- **Deal Stage**: Visual pipeline bar at the top. Click a stage to move the deal. Stages are configurable per pipeline.\n- **Amount**: Currency field for the deal value.\n- **Close Date**: Date picker. Drives forecasting reports.\n- **Deal Owner**: Dropdown to assign ownership.\n- **Deal Type**: Dropdown. Common values: New Business, Existing Business.\n- **Priority**: Dropdown. Values: Low, Medium, High.\n- **Forecast Category**: Auto-calculated or manually set. Values: Omit, Pipeline, Best Case, Commit, Closed.\n\n## Common Actions\n- **Move Stage**: Click a stage in the pipeline bar or use the "Move to" dropdown to advance the deal.\n- **Mark as Won**: Move to "Closed Won" stage. Triggers associated workflows and revenue tracking.\n- **Mark as Lost**: Move to "Closed Lost" stage. Prompts for a close-lost reason.\n- **Create Quote**: Generate a sales quote from the deal. Pre-populates with deal amount and line items.\n- **Add Line Items**: Open the line item editor to add products or services to the deal.\n- **Create Task**: Create a follow-up task associated with the deal.\n\n## Related Panels\n- **Contacts**: People involved in this deal.\n- **Companies**: Organizations associated with the deal.\n- **Line Items**: Products/services with quantities, pricing, and discounts.\n- **Quotes**: Generated quotes linked to this deal.\n- **Activity Timeline**: All interactions related to this deal.\n\n## UI Element Selectors\n- Pipeline stage bar: `[data-selenium-test="deal-stage-tracker"]`\n- Deal Amount: `[data-selenium-test="property-input-amount"]`\n- Close Date: `[data-selenium-test="property-input-closedate"]`\n- Deal Owner: `[data-selenium-test="property-input-hubspot_owner_id"]`\n- Create Quote: `[data-selenium-test="quote-create-button"]`',
  '{"Pipeline Stage Bar": "[data-selenium-test=\"deal-stage-tracker\"]", "Deal Amount": "[data-selenium-test=\"property-input-amount\"]", "Close Date": "[data-selenium-test=\"property-input-closedate\"]", "Deal Owner": "[data-selenium-test=\"property-input-hubspot_owner_id\"]", "Create Quote": "[data-selenium-test=\"quote-create-button\"]"}'::jsonb
),
(
  'hubspot',
  'deals-board',
  E'---\nlayer: vendor\napp: hubspot\nscreen: deals-board\nversion: "2026"\nlast_updated: 2026-04-11\nsource: "manual-mapping-v1"\n---\n\n# HubSpot: Deals Board View\n\n## Navigation\nAccessed via: Sales > Deals (default board view)\n\n## Overview\nThe deals board is a Kanban-style view of your sales pipeline. Each column represents a deal stage, and deal cards can be dragged between columns to update their stage. The board provides a visual overview of pipeline health, showing deal count and total value per stage at the top of each column.\n\n## Key Features\n- **Pipeline Selector**: Dropdown at the top to switch between different sales pipelines.\n- **Deal Cards**: Each card shows deal name, amount, close date, contact name, and deal owner avatar.\n- **Drag and Drop**: Move deal cards between columns to change their stage. The stage update is saved immediately.\n- **Column Summaries**: Each column header shows the count of deals and total weighted value.\n- **Sort Options**: Sort deals within a column by deal name, amount, close date, or last activity.\n\n## Common Actions\n- **Create Deal**: "+" button at the top of any column. Opens a quick-create panel pre-set to that stage.\n- **Filter Deals**: Use the filter bar to narrow by deal owner, close date range, amount range, or custom properties.\n- **Switch to List View**: Toggle between board and table view using the view switcher at the top.\n- **Edit Board Properties**: Customize which properties appear on deal cards.\n- **Bulk Actions**: Switch to list view for bulk operations (board view is single-deal interaction only).\n\n## Pipeline Management\n- **Add Stage**: Edit pipeline settings to add new stages. Stages have win probability percentages.\n- **Reorder Stages**: Drag stages in pipeline settings to change their order.\n- **Stage Automation**: Configure automated actions when deals enter or leave a stage.\n\n## UI Element Selectors\n- Pipeline selector: `[data-selenium-test="pipeline-select"]`\n- Deal card: `[data-selenium-test="deal-card"]`\n- Board column: `[data-selenium-test="board-column"]`\n- Create deal button: `[data-selenium-test="board-create-deal"]`\n- View toggle: `[data-selenium-test="view-toggle"]`',
  '{"Pipeline Selector": "[data-selenium-test=\"pipeline-select\"]", "Deal Card": "[data-selenium-test=\"deal-card\"]", "Board Column": "[data-selenium-test=\"board-column\"]", "Create Deal": "[data-selenium-test=\"board-create-deal\"]", "View Toggle": "[data-selenium-test=\"view-toggle\"]"}'::jsonb
),
(
  'hubspot',
  'ticket-detail',
  E'---\nlayer: vendor\napp: hubspot\nscreen: ticket-detail\nversion: "2026"\nlast_updated: 2026-04-11\nsource: "manual-mapping-v1"\n---\n\n# HubSpot: Ticket Detail Page\n\n## Navigation\nAccessed via: Service > Tickets > [Ticket Name]\n\n## Overview\nThe ticket detail page is the primary workspace for managing a support ticket in HubSpot Service Hub. It shows ticket properties, the conversation thread, and associations with contacts and companies. The ticket pipeline stage is displayed at the top, similar to the deal detail page.\n\n## Key Fields\n- **Ticket Name**: Short description of the issue.\n- **Ticket Status**: Pipeline stage indicator at the top. Common stages: New, Waiting on Contact, Waiting on Us, Closed.\n- **Priority**: Dropdown. Values: Low, Medium, High.\n- **Category**: Dropdown for ticket categorization (configurable).\n- **Source**: How the ticket was created (Email, Chat, Phone, Form, etc.).\n- **Ticket Owner**: Dropdown to assign the ticket to a support agent.\n- **Create Date**: Auto-set when the ticket is created.\n- **Close Date**: Auto-set when moved to a closed stage.\n\n## Common Actions\n- **Reply**: Send a response to the contact via email. The reply appears in the conversation thread.\n- **Add Note**: Internal note visible only to your team. Does not notify the contact.\n- **Change Status**: Click a stage in the pipeline bar or use the dropdown to update ticket status.\n- **Merge Tickets**: Combine duplicate tickets into a single record.\n- **Create Task**: Schedule a follow-up action for the ticket.\n- **Associate Contact**: Link the ticket to a specific contact or company.\n\n## Conversation Thread\n- **Email Thread**: Shows the full email conversation between the agent and contact.\n- **Internal Notes**: Yellow-highlighted notes only visible to the support team.\n- **Chat Transcripts**: If the ticket originated from live chat, the full transcript is embedded.\n\n## UI Element Selectors\n- Ticket status pipeline: `[data-selenium-test="ticket-stage-tracker"]`\n- Priority dropdown: `[data-selenium-test="property-input-hs_ticket_priority"]`\n- Reply editor: `[data-selenium-test="email-reply-editor"]`\n- Ticket Owner: `[data-selenium-test="property-input-hubspot_owner_id"]`\n- Conversation thread: `[data-selenium-test="conversation-thread"]`',
  '{"Ticket Status": "[data-selenium-test=\"ticket-stage-tracker\"]", "Priority": "[data-selenium-test=\"property-input-hs_ticket_priority\"]", "Reply Editor": "[data-selenium-test=\"email-reply-editor\"]", "Ticket Owner": "[data-selenium-test=\"property-input-hubspot_owner_id\"]", "Conversation Thread": "[data-selenium-test=\"conversation-thread\"]"}'::jsonb
),
(
  'hubspot',
  'dashboard',
  E'---\nlayer: vendor\napp: hubspot\nscreen: dashboard\nversion: "2026"\nlast_updated: 2026-04-11\nsource: "manual-mapping-v1"\n---\n\n# HubSpot: Reports Dashboard\n\n## Navigation\nAccessed via: Reporting > Dashboards\n\n## Overview\nThe reports dashboard displays a collection of report widgets arranged in a customizable grid layout. Dashboards provide at-a-glance visibility into sales performance, marketing metrics, service KPIs, or any combination. HubSpot includes several default dashboards (Sales, Marketing, Service) and allows users to create custom ones.\n\n## Key Features\n- **Dashboard Selector**: Dropdown at the top to switch between dashboards. Star a dashboard to set it as your default.\n- **Date Range Filter**: Global date range that applies to all reports on the dashboard. Supports preset ranges (This Month, Last Quarter) and custom date ranges.\n- **Report Widgets**: Individual report cards showing charts, tables, or single metrics. Each widget can be resized and repositioned.\n- **Frequency Filter**: Filter data by day, week, month, or quarter for time-series reports.\n\n## Common Actions\n- **Add Report**: Click "Add report" to add an existing report or create a new one directly on the dashboard.\n- **Create Dashboard**: "Create dashboard" button. Choose blank or from a template.\n- **Edit Layout**: Enter edit mode to drag, resize, and rearrange report widgets.\n- **Share Dashboard**: Send a dashboard link to teammates or set up recurring email delivery.\n- **Export**: Download dashboard as a PDF or image for stakeholder presentations.\n- **Clone Dashboard**: Duplicate an existing dashboard as a starting point for a new one.\n\n## Report Types\n- **Bar/Column Charts**: Compare metrics across categories or time periods.\n- **Line Charts**: Track trends over time (e.g., deals closed per month).\n- **Pie/Donut Charts**: Show proportional breakdowns.\n- **KPI Widgets**: Single-number metrics with trend indicators.\n- **Tables**: Detailed data grids with sorting and filtering.\n\n## UI Element Selectors\n- Dashboard selector: `[data-selenium-test="dashboard-selector"]`\n- Add report button: `[data-selenium-test="add-report-button"]`\n- Date range picker: `[data-selenium-test="date-range-picker"]`\n- Report widget: `[data-selenium-test="report-widget"]`\n- Edit layout button: `[data-selenium-test="edit-dashboard-button"]`',
  '{"Dashboard Selector": "[data-selenium-test=\"dashboard-selector\"]", "Add Report": "[data-selenium-test=\"add-report-button\"]", "Date Range": "[data-selenium-test=\"date-range-picker\"]", "Report Widget": "[data-selenium-test=\"report-widget\"]", "Edit Layout": "[data-selenium-test=\"edit-dashboard-button\"]"}'::jsonb
),
(
  'hubspot',
  'workflows',
  E'---\nlayer: vendor\napp: hubspot\nscreen: workflows\nversion: "2026"\nlast_updated: 2026-04-11\nsource: "manual-mapping-v1"\n---\n\n# HubSpot: Workflows\n\n## Navigation\nAccessed via: Automation > Workflows\n\n## Overview\nThe workflows screen is where you create and manage automated business processes in HubSpot. Workflows can trigger on contact, company, deal, ticket, or quote events and execute sequences of actions like sending emails, updating properties, creating tasks, or calling webhooks. The main view is a list of all workflows with status, enrollment count, and last edit date.\n\n## Key Features\n- **Workflow List**: Table showing all workflows with name, type, status (Active/Inactive), enrolled count, and last modified date.\n- **Folder Organization**: Organize workflows into folders for easier management.\n- **Search and Filter**: Search by name, filter by type (Contact, Company, Deal, Ticket, Custom Object), status, or folder.\n- **Performance Metrics**: Each workflow shows total enrollments, currently enrolled, and goal completion rate.\n\n## Common Actions\n- **Create Workflow**: Click "Create workflow" and choose a type. Options: Start from scratch or use a template.\n- **Clone Workflow**: Duplicate an existing workflow to use as a starting point.\n- **Toggle Active/Inactive**: Turn a workflow on or off without deleting it. Pausing stops new enrollments but lets in-progress ones complete.\n- **Edit Workflow**: Opens the visual workflow editor with drag-and-drop action blocks.\n- **View History**: See a log of all enrollments, completions, and errors for a workflow.\n- **Delete Workflow**: Permanently remove. Requires confirmation. Active workflows must be deactivated first.\n\n## Workflow Editor\n- **Trigger Block**: Defines when a contact/record enters the workflow (form submission, property change, list membership, etc.).\n- **Action Blocks**: Steps executed in sequence: send email, set property, create task, if/then branch, delay, webhook.\n- **If/Then Branches**: Conditional logic that splits the workflow path based on property values or behaviors.\n- **Goal Criteria**: Optional exit condition. Records that meet the goal are removed from the workflow.\n\n## UI Element Selectors\n- Create workflow button: `[data-selenium-test="create-workflow-button"]`\n- Workflow list table: `[data-selenium-test="workflows-table"]`\n- Search input: `[data-selenium-test="workflow-search-input"]`\n- Status toggle: `[data-selenium-test="workflow-status-toggle"]`\n- Filter dropdown: `[data-selenium-test="workflow-type-filter"]`',
  '{"Create Workflow": "[data-selenium-test=\"create-workflow-button\"]", "Workflow Table": "[data-selenium-test=\"workflows-table\"]", "Search Input": "[data-selenium-test=\"workflow-search-input\"]", "Status Toggle": "[data-selenium-test=\"workflow-status-toggle\"]", "Type Filter": "[data-selenium-test=\"workflow-type-filter\"]"}'::jsonb
),
(
  'hubspot',
  'email',
  E'---\nlayer: vendor\napp: hubspot\nscreen: email\nversion: "2026"\nlast_updated: 2026-04-11\nsource: "manual-mapping-v1"\n---\n\n# HubSpot: Email Marketing\n\n## Navigation\nAccessed via: Marketing > Email\n\n## Overview\nThe email screen is the hub for creating and managing marketing emails in HubSpot. It shows a list of all email campaigns with their status (Draft, Scheduled, Sent), send date, open rate, click rate, and unsubscribe count. From here you can create new emails, clone existing ones, or dive into performance analytics.\n\n## Key Features\n- **Email List**: Table of all marketing emails with name, type (Regular, Automated, A/B), status, and performance metrics.\n- **Tabs**: Switch between Regular, Automated, Blog/RSS, and All email types.\n- **Search and Filter**: Search by email name, filter by campaign, status, or type.\n- **Performance Overview**: Quick stats for each email: sent count, open rate, click rate, bounce rate.\n\n## Common Actions\n- **Create Email**: Click "Create email" to start a new email. Choose Regular, Automated, or A/B test.\n- **Edit Email**: Opens the drag-and-drop email editor with content blocks, design tools, and personalization tokens.\n- **Clone Email**: Duplicate an existing email to reuse as a template.\n- **Send/Schedule**: After editing, choose to send immediately or schedule for a future date/time.\n- **A/B Test**: Create two variants with different subject lines, content, or send times. HubSpot automatically picks the winner based on opens or clicks.\n- **Analyze**: Click into a sent email to view detailed analytics: delivery, engagement, clicks by link, device breakdown, and contact-level activity.\n\n## Email Editor\n- **Drag-and-Drop Blocks**: Text, image, button, divider, video, social sharing, and custom HTML modules.\n- **Personalization Tokens**: Insert contact properties (first name, company name) using tokens like `{{contact.firstname}}`.\n- **Preview and Test**: Preview in desktop/mobile views and send test emails before launching.\n- **Smart Content**: Show different content based on contact list membership, lifecycle stage, or device type.\n\n## UI Element Selectors\n- Create email button: `[data-selenium-test="create-email-button"]`\n- Email list table: `[data-selenium-test="email-table"]`\n- Search input: `[data-selenium-test="email-search-input"]`\n- Type tabs: `[data-selenium-test="email-type-tabs"]`\n- Send button: `[data-selenium-test="email-send-button"]`',
  '{"Create Email": "[data-selenium-test=\"create-email-button\"]", "Email Table": "[data-selenium-test=\"email-table\"]", "Search Input": "[data-selenium-test=\"email-search-input\"]", "Type Tabs": "[data-selenium-test=\"email-type-tabs\"]", "Send Button": "[data-selenium-test=\"email-send-button\"]"}'::jsonb
),
(
  'hubspot',
  'forms',
  E'---\nlayer: vendor\napp: hubspot\nscreen: forms\nversion: "2026"\nlast_updated: 2026-04-11\nsource: "manual-mapping-v1"\n---\n\n# HubSpot: Forms\n\n## Navigation\nAccessed via: Marketing > Forms\n\n## Overview\nThe forms screen lists all HubSpot forms used for lead capture across your website, landing pages, and pop-ups. Forms collect contact information and feed data into the CRM, triggering workflows and list enrollments. The list view shows form name, type, submissions count, page views, and conversion rate.\n\n## Key Features\n- **Form List**: Table showing all forms with name, type (Embedded, Standalone, Pop-up), status, submissions, views, and conversion rate.\n- **Tabs**: Filter by form type: All Forms, Regular Forms, Pop-up Forms, and Non-HubSpot Forms (tracked external forms).\n- **Folder Organization**: Organize forms into folders for better management.\n- **Search**: Search forms by name.\n\n## Common Actions\n- **Create Form**: Click "Create form" to start building. Choose between Embedded Form, Standalone Page, Pop-up Form, or Dropdown Banner.\n- **Edit Form**: Opens the form editor where you add/remove fields, configure validation, and set up form submission actions.\n- **Clone Form**: Duplicate a form to use as a starting point for a new one.\n- **Embed Code**: Copy the form embed code to place on external websites.\n- **View Submissions**: Click into a form to see all submissions with contact details and submitted values.\n- **Delete Form**: Remove a form. Active forms on published pages will stop collecting data.\n\n## Form Editor\n- **Field Types**: Single-line text, multi-line text, dropdown, radio, checkbox, date picker, file upload, and more.\n- **Field Properties**: Set labels, placeholder text, help text, required/optional, default values, and validation rules.\n- **Progressive Profiling**: Automatically swap out fields that are already known for the contact, collecting new information with each visit.\n- **Form Options**: Thank-you message or redirect URL, notification emails, GDPR consent fields, and recaptcha.\n- **Styling**: Customize form appearance including colors, fonts, button text, and layout.\n\n## UI Element Selectors\n- Create form button: `[data-selenium-test="create-form-button"]`\n- Forms table: `.private-form__field`\n- Search input: `[data-selenium-test="forms-search-input"]`\n- Submission count: `[data-selenium-test="form-submissions-count"]`\n- Form type tabs: `[data-selenium-test="form-type-tabs"]`',
  '{"Create Form": "[data-selenium-test=\"create-form-button\"]", "Forms Table": ".private-form__field", "Search Input": "[data-selenium-test=\"forms-search-input\"]", "Submissions Count": "[data-selenium-test=\"form-submissions-count\"]", "Form Type Tabs": "[data-selenium-test=\"form-type-tabs\"]"}'::jsonb
)

ON CONFLICT (app, screen) DO UPDATE SET
  content = EXCLUDED.content,
  element_selectors = EXCLUDED.element_selectors,
  updated_at = now();

